// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
//
// 2.8.5 | 2023-09-22 | mmcc |  DFCT0011517 - New button in the platform that is leading to creating an Empty User Out of office
//           record & that should NOT be created /allowed
//           Created Business Rule to show a toast error message if logged in user does not have permission to create/update;
//           All fields are greyed out
// 2.8.5 | 2023-10-02 | mmcc | DFCT0012195 – Spelling error, should not display in the Toast message "User does not have 
//           permisions to add or update an out of office schedule
//           Updated Business Rule to toast error message with word permissions
//           Updated Message Key and Message to use word permissions
//
//------------------------------------------------------------------------------------------------------------------------
(function executeRule(current, previous /*null when async*/) {
	var canCreateOOO = new Organization_uiAction().canCreateOOO(current.getValue('u_user'));
	var userName = current.getDisplayValue('u_user');

	if (canCreateOOO == false) {
		current.setAbortAction(true);
		gs.addErrorMessage(gs.getMessage('Tasker - User does not have permissions to add or update an out of office schedule for user {0}',
										[userName]));
	}
})(current, previous);
